const items = $input.all();
if (!items.length) {
  return [{ json: {
    status: 'OK', count: 0,
    email_subject: null, email_body: null,
    summary: 'Alle DB-Konsistenzpruefungen bestanden.'
  }}];
}
const CHECK_LABELS = {
  keine_preise:     'Aktive Slots ohne Preis',
  negative_qty:     'Negative Lagermengen',
  wf3_stale:        'WF3 Verkaufsworkflow haengt',
  alte_warnungen:   'Alte ungeloeste Warnungen (>7 Tage)',
  pending_proposals:'Offene Rechnungsvorschlaege (>14 Tage)',
};
const grouped = {};
for (const { json: row } of items) {
  if (!grouped[row.check_type]) grouped[row.check_type] = [];
  grouped[row.check_type].push(row.message);
}
const lines = Object.entries(grouped).map(([type, msgs]) => {
  const label = CHECK_LABELS[type] || type;
  return '<h3 style="color:#c0392b">' + label + ' (' + msgs.length + ')</h3><ul>' +
    msgs.map(m => '<li>' + m + '</li>').join('') + '</ul>';
}).join('');
const count = items.length;
const ts = new Date().toISOString();
return [{ json: {
  status: 'FEHLER', count, grouped,
  email_subject: '[DB-Check] ' + count + ' Problem' + (count !== 1 ? 'e' : '') + ' — Automatenlager',
  email_body: '<h2 style="color:#c0392b">DB-Konsistenzpruefung: ' + count +
    ' Problem' + (count !== 1 ? 'e' : '') + '</h2>' + lines +
    '<hr><p style="color:#888;font-size:12px">WF-Val Check: ' + ts + '</p>'
}}];

